import html
import json
from dataclasses import dataclass
from pathlib import Path

from typing import Any


@dataclass(frozen=True)
class LogMessage:
    agent: str
    agent_instance: int
    timestamp: str
    role: str
    content: str
    reasoning: str | None = None
    tool_calls: list[dict[str, Any]] | None = None
    tool_id: str | None = None
    tool_name: str | None = None


def parse_log_file(log_path: Path) -> list[LogMessage]:
    messages: list[LogMessage] = []
    with open(log_path, encoding="utf-8") as log_file:
        for line in log_file:
            line_stripped = line.strip()
            if not line_stripped:
                continue
            record = json.loads(line_stripped)
            source = record["source"]
            message = record["message"]
            messages.append(_build_log_message(source, message))
    return messages


def _build_log_message(source: dict[str, Any], message: dict[str, Any]) -> LogMessage:
    return LogMessage(
        agent=source["agent"],
        agent_instance=source["agent_instance"],
        timestamp=record_timestamp(message),
        role=message["role"],
        content=message.get("content", ""),
        reasoning=message.get("reasoning"),
        tool_calls=message.get("tool_calls"),
        tool_id=message.get("id"),
        tool_name=message.get("name"),
    )


def record_timestamp(message: dict[str, Any]) -> str:
    return message.get("at", "")


def escape(text: str) -> str:
    return html.escape(text, quote=True)


def _agent_label(agent: str, instance: int) -> str:
    return f"{agent} ({instance})"


def _format_tool_arguments(arguments_str: str) -> str:
    try:
        parsed = json.loads(arguments_str)
        return json.dumps(parsed, indent=2)
    except (json.JSONDecodeError, TypeError):
        return arguments_str


def _render_tool_call(tool_call: dict[str, Any]) -> str:
    tool_id = tool_call.get("id", "")
    tool_name = tool_call.get("name", "")
    arguments = _format_tool_arguments(tool_call.get("arguments", ""))
    return (
        f'<details class="tool-call">'
        f"<summary>{escape(tool_name)} <code>{escape(tool_id)}</code></summary>"
        f"<pre>{escape(arguments)}</pre>"
        f"</details>"
    )


def _render_tool_output(tool_id: str | None, content: str) -> str:
    content_escaped = escape(content)
    preview = content_escaped[:120]
    if len(content_escaped) > 120:
        preview += "..."
    return (
        f'<details class="tool-output">'
        f"<summary>Tool response <code>{escape(tool_id)}</code>: {escape(tool_name_from_id(tool_id))}</summary>"
        f"<pre>{content_escaped}</pre>"
        f"</details>"
    )


def tool_name_from_id(tool_id: str | None) -> str:
    if not tool_id:
        return "unknown"
    return tool_id


def _render_system(content: str) -> str:
    escaped_content = escape(content)
    preview = escaped_content[:100]
    if len(escaped_content) > 100:
        preview += "..."
    return (
        f'<details class="message-system">'
        f"<summary>System</summary>"
        f"<div class='message-content'><pre>{preview}</pre></div>"
        f"<details>"
        f"<div class='message-content'><pre>{escaped_content}</pre></div>"
        f"</details>"
        f"</details>"
    )


def _render_user(content: str) -> str:
    escaped_content = escape(content)
    return (
        f'<div class="message user">'
        f"<div class='message-content'><pre>{escaped_content}</pre></div>"
        f"</div>"
    )


def _render_assistant(content: str, reasoning: str | None, tool_calls: list[dict[str, Any]] | None) -> str:
    parts: list[str] = []
    if reasoning:
        parts.append(_render_reasoning(reasoning))
    if content:
        parts.append(f"<div class='message-content'><pre>{escape(content)}</pre></div>")
    if tool_calls:
        for tool_call in tool_calls:
            parts.append(_render_tool_call(tool_call))
    return f"<div class='message assistant'>{''.join(parts)}</div>"


def _render_reasoning(reasoning: str) -> str:
    escaped = escape(reasoning)
    return (
        f'<details class="reasoning">'
        f"<summary>Reasoning</summary>"
        f"<pre>{escaped}</pre>"
        f"</details>"
    )


def render_html(messages: list[LogMessage], log_path: Path) -> str:
    agent_name = messages[0].agent if messages else "Unknown"
    sections = [_header_section(messages, agent_name, log_path)]
    for message in messages:
        sections.append(_message_section(message))
    return (
        "<!DOCTYPE html>\n"
        "<html lang='en'>"
        "<head>"
        "<meta charset='utf-8'>"
        "<meta name='viewport' content='width=device-width, initial-scale=1'>"
        "<title>Agent Log - {agent}</title>"
        "<style>{style}</style>"
        "</head>"
        "<body>{body}</body>"
        "</html>"
    ).format(
        agent=escape(agent_name),
        style=_css_styles(),
        body="\n".join(sections),
    )


def _header_section(messages: list[LogMessage], agent_name: str, log_path: Path) -> str:
    entry_count = len(messages)
    timestamp = messages[0].timestamp if messages else ""
    return (
        f'<div class="header">'
        f"<h1>{escape(agent_name)} - Agent Log</h1>"
        f"<p>{escape(log_path.name)} | {entry_count} entries | {escape(timestamp)}</p>"
        f"</div>"
    )


def _message_section(message: LogMessage) -> str:
    label = _agent_label(message.agent, message.agent_instance)
    timestamp = message.timestamp
    timestamp_display = _format_timestamp_display(timestamp)
    body = _render_message_body(message)
    return (
        f'<div class="log-entry">'
        f"<div class='log-meta'><span class='timestamp'>{timestamp_display}</span> "
        f"<span class='agent-label'>{escape(label)}</span></div>"
        f"<div class='log-body'>{body}</div>"
        f"</div>"
    )


def _format_timestamp_display(timestamp: str) -> str:
    if not timestamp:
        return ""
    try:
        from datetime import datetime

        dt = datetime.fromisoformat(timestamp)
        return dt.strftime("%Y-%m-%d %H:%M:%S")
    except (ValueError, TypeError):
        return timestamp


def _render_message_body(message: LogMessage) -> str:
    if message.role == "system":
        return _render_system(message.content)
    if message.role == "user":
        return _render_user(message.content)
    if message.role == "assistant":
        return _render_assistant(
            message.content,
            message.reasoning,
            message.tool_calls,
        )
    if message.role == "tool":
        return _render_tool_output(message.tool_id, message.content)
    return _render_user(message.content)


