    messages: list[LogMessage] = []
    with open(log_path, encoding="utf-8") as log_file:
        for line in log_file:
            line_stripped = line.strip()
            if not line_stripped:
                continue
            record = _parse_record(line_stripped)
            messages.append(_build_log_message(record))
    return messages


def _parse_record(line: str) -> dict[str, Any]:
    record = json.loads(line)
    source = record["source"]
    message = record["message"]
    return {"source": source, "message": message, "at": record.get("at", "")}


def _build_log_message(record: dict[str, Any]) -> LogMessage:
    source = record["source"]
    message = record["message"]
    return LogMessage(
        agent=source["agent"],
        agent_instance=source["agent_instance"],
        timestamp=_format_timestamp(record["at"]),
        role=message["role"],
        content=message.get("content", ""),
        reasoning=message.get("reasoning"),
        tool_calls=message.get("tool_calls"),
        tool_id=message.get("id"),
        tool_name=message.get("name"),
    )


def _format_timestamp(iso_string: str) -> str:
    if not iso_string:
        return ""
    try:
        dt = datetime.fromisoformat(iso_string)
        return dt.strftime("%Y-%m-%d %H:%M:%S")
    except (ValueError, TypeError):
        return iso_string


def _escape(text: str) -> str:
    return html_module.escape(text, quote=True)


def _agent_label(agent: str, instance: int) -> str:
    return f"{agent} ({instance})"


def render_html(messages: list[LogMessage], log_path: Path) -> str:
    agent_name = _first_agent(messages)
    parts = ["<!DOCTYPE html>", "<html lang='en'>", "<head>"]
    parts.append("<meta charset='utf-8'>")
    parts.append("<meta name='viewport' content='width=device-width, initial-scale=1'>")
    parts.append(f"<title>Agent Log - {_escape(agent_name)}</title>")
    parts.append(f"<style>{_css_styles()}</style>")
    parts.append("</head><body>")
    parts.append(_render_header(messages, agent_name, log_path))
    for message in messages:
        parts.append(_render_message(message))
    parts.append("</body></html>")
    return "\n".join(parts)


def _first_agent(messages: list[LogMessage]) -> str:
    if messages:
        return messages[0].agent
    return "Unknown"


def _render_header(messages: list[LogMessage], agent_name: str, log_path: Path) -> str:
    entry_count = len(messages)
    timestamp = messages[0].timestamp if messages else ""
    return (
        f'<div class="header">'
        f"<h1>{_escape(agent_name)} - Agent Log</h1>"
        f"<p>{_escape(log_path.name)} | {entry_count} entries | {_escape(timestamp)}</p>"
        f"</div>"
    )


def _render_message(message: LogMessage) -> str:
    label = _agent_label(message.agent, message.agent_instance)
    body = _render_message_body(message)
    return (
        f'<div class="log-entry">'
        f"<div class='log-meta'><span class='timestamp'>{_escape(message.timestamp)}</span> "
        f"<span class='agent-label'>{_escape(label)}</span></div>"
        f"<div class='log-body'>{body}</div>"
        f"</div>"
    )


def _render_message_body(message: LogMessage) -> str:
    role = message.role
    if role == "system":
        return _render_system(message.content)
    if role == "user":
        return _render_user(message.content)
    if role == "assistant":
        return _render_assistant(message.content, message.reasoning, message.tool_calls)
    if role == "tool":
        return _render_tool_output(message.tool_id, message.content)
    return _render_user(message.content)


def _render_system(content: str) -> str:
    escaped = _escape(content)
    preview = _truncate_preview(escaped, 100)
    return (
        f'<details class="message-system">'
        f"<summary>System</summary>"
        f"<div class='message-content'><pre>{preview}</pre></div>"
        f"<details>"
        f"<div class='message-content'><pre>{escaped}</pre></div>"
        f"</details>"
        f"</details>"
    )


def _truncate_preview(text: str, max_length: int) -> str:
    if len(text) <= max_length:
        return text
    return text[:max_length] + "..."


def _render_user(content: str) -> str:
    escaped = _escape(content)
    return (
        f'<div class="message user">'
        f"<div class='message-content'><pre>{escaped}</pre></div>"
        f"</div>"
