def _render_assistant(content: str, reasoning: str | None, tool_calls: list[dict[str, Any]] | None) -> str:
    parts = _build_assistant_parts(reasoning, content, tool_calls)
    return f"<div class='message assistant'>{parts}</div>"


def _build_assistant_parts(reasoning: str | None, content: str, tool_calls: list[dict[str, Any]] | None) -> str:
    parts: list[str] = []
    if reasoning:
        parts.append(_render_reasoning(reasoning))
