        f"<summary>{_escape(tool_name)} <code>{_escape(tool_id)}</code></summary>"
        f"<pre>{_escape(arguments)}</pre>"
        f"</details>"
    )


def _render_tool_output(tool_id: str | None, content: str) -> str:
    escaped_content = _escape(content)
    return (
        f'<details class="tool-output">'
        f"<summary>Tool response <code>{_escape(tool_id)}</code></summary>"
        f"<pre>{escaped_content}</pre>"
